1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	interface Scenario {
11	  customer: { yearsWithMHPCO: number };
12	  steps: QuoteStep[];
13	}
14	
15	const BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	};
19	
20	const FIRST_INSURANCE_MULTIPLIER = 1.1;
21	const PROCESSING_FEE = 5;
22	const ROUNDING_PRECISION = 6;
23	
24	const quotePremium = (items: Item[]): number => {
25	  let total = 0;
26	  for (const item of items) {
27	    const base = BASE_PREMIUM[item.type];
28	    total += base * FIRST_INSURANCE_MULTIPLIER;
29	  }
30	  const totalWithFee = total + PROCESSING_FEE;
31	  return Math.ceil(Number(totalWithFee.toFixed(ROUNDING_PRECISION)));
32	};
33	
34	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
35	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
36	  return { results };
37	};
